local Widget = require "widgets/widget" local Image = require "widgets/image" local Text = require "widgets/text" local Screen = require "widgets/screen" local Button = require "widgets/button" local Spinner = require "widgets/spinner" local dycguis = {} dycguis.Init = function(self, data) if self.initialized then return end self.initialized = true self.localization = data.localization self.multiLineScale = data.multiLineScale self.textWidthScale = data.textWidthScale self.language = data.language end local function IsRail() return string.upper(PLATFORM) == "WIN32" end local function IsDST() return false end local function DYCGetPlayer() if IsDST() then return ThePlayer else return GetPlayer() end end local function DYCGetWorld() if IsDST() then return TheWorld else return GetWorld() end end local GetString = function(key, default) local strs = dycguis.localization.strings or dycguis.localization:GetStrings() return strs:GetString(key, default) end local GetScreenScale = function() local sw, sh = TheSim:GetScreenSize() return sw / 0x780 end local GetMouseScreenPos = function() return TheSim:GetScreenPos(TheInput:GetWorldPosition():Get()) end local RGBAColor = function(r, g, b, a) return {r = r or 0x1, g = g or 0x1, b = b or 0x1, a = a or 0x1, Get = function(self) return self.r, self.g, self.b, self.a end, R = function(self, r) self.r = r return self end, G = function(self, g) self.g = g return self end, B = function(self, b) self.b = b return self end, A = function(self, a) self.a = a return self end,} end local Lerp = function(a, b, p) return a + (b - a) * p end local function StrSpl(str, sep) if sep == nil then sep = "%s" end local t = {} local i = 0x1 for s in string.gmatch(str, "([^"..sep.."]+)" ) do t[i] = s i = i + 0x1 end return t end local TableContains = function(t, value) for k, v in pairs(t) do if v == value then return true end end return false end local TableAdd = function(t, value) if not TableContains(t, value) then table.insert(t, value) end end local TableGetIndex = function(t, value) for k, v in pairs(t) do if v == value then return k end end end local TableRemoveValue = function(t, value) local index = TableGetIndex(t, value) if index then table.remove(t, index) end end local DYC_Root = Class(Widget, function(self, data) Widget._ctor(self, "DYC_Root" ) self.keepTop = data.keepTop self.moveLayerTimer = 0x0 if data.keepTop then self:StartUpdating() end end) function DYC_Root:OnUpdate(dt) dt = dt or 0x0 self.moveLayerTimer = self.moveLayerTimer + dt if self.keepTop and self.moveLayerTimer > 0.5 then self.moveLayerTimer = 0x0 self:MoveToFront() end end dycguis.Root = DYC_Root local DYC_Text = Class(Text, function(self, font, size, text, hittest) if font and type(font) == "table" then local data = font Text._ctor(self, data.font or NUMBERFONT, data.fontSize or 0x1e, data.text) if data.color then local c = data.color self:SetColor(c.r or c[0x1] or 0x1, c.g or c[0x2] or 0x1, c.b or c[0x3] or 0x1, c.a or c[0x4] or 0x1) end if data.regionSize then self:SetRegionSize(data.regionSize.w, data.regionSize.h) end self.alignH = data.alignH self.alignV = data.alignV self.focusFn = data.focusFn self.unfocusFn = data.unfocusFn self.hittest = data.hittest else Text._ctor(self, font or NUMBERFONT, size or 0x1e, text) self.hittest = hittest if text then self:SetText(text) end end end) function DYC_Text:GetImage() if not self.image then self.image = self:AddChild(Image( "images/ui.xml" , "button.tex" )) self.image:MoveToBack() self.image:SetTint(0x0, 0x0, 0x0, 0x0) end return self.image end function DYC_Text:SetText(str) local oldWidth = self:GetWidth() local oldHeight = self:GetHeight() local pos = self:GetPosition() self:SetString(str) if self.alignH and self.alignH ~= ANCHOR_MIDDLE then local newWidth = self:GetWidth() pos.x = pos.x + (newWidth - oldWidth) / 0x2 * (self.alignH == ANCHOR_LEFT and 0x1 or - 0x1) end if self.alignV and self.alignV ~= ANCHOR_MIDDLE then local newHeight = self:GetHeight() pos.y = pos.y + (newHeight - oldHeight) / 0x2 * (self.alignV == ANCHOR_BOTTOM and 0x1 or - 0x1) end if self.alignH or self.alignV then self:SetPosition(pos) end if self.hittest then self:GetImage():SetSize(self:GetSize()) end end function DYC_Text:SetColor(...) self:SetColour(...) end function DYC_Text:GetRegionSize() local w, h = DYC_Text._base.GetRegionSize(self) w = w * (dycguis.textWidthScale or 0x1) return w, h end function DYC_Text:GetWidth() local w, h = self:GetRegionSize() w = w < 0x2710 and w or 0x0 return w end function DYC_Text:GetHeight() local w, h = self:GetRegionSize() h = h < 0x2710 and h or 0x0 return h end function DYC_Text:GetSize() local w, h = self:GetRegionSize() w = w < 0x2710 and w or 0x0 h = h < 0x2710 and h or 0x0 return w, h end function DYC_Text:OnGainFocus() DYC_Text._base.OnGainFocus(self) if self.focusFn then self.focusFn(self) end end function DYC_Text:OnLoseFocus() DYC_Text._base.OnLoseFocus(self) if self.unfocusFn then self.unfocusFn(self) end end function DYC_Text:AnimateIn(speed) self.textString = self.string self.animSpeed = speed or 0x3c self.animIndex = 0x0 self.animTimer = 0x0 self:SetText( "" ) self:StartUpdating() end function DYC_Text:OnUpdate(dt) dt = dt or 0x0 if DYC_Text._base.OnUpdate then DYC_Text._base.OnUpdate(self, dt) end if dt > 0x0 and self.animIndex and self.textString and #self.textString > 0x0 then self.animTimer = self.animTimer + dt if self.animTimer > 0x1 / self.animSpeed then self.animTimer = 0x0 self.animIndex = self.animIndex + 0x1 if self.animIndex > #self.textString then self.animIndex = nil self:SetText(self.textString) else local ascii = string.byte(string.sub(self.textString, self.animIndex, self.animIndex)) if ascii and ascii > 0x7f then self.animIndex = self.animIndex + 0x2 end self:SetText(string.sub(self.textString, 0x1, self.animIndex)) end end end end dycguis.Text = DYC_Text local DYC_SlicedImage = Class(Widget, function(self, data) Widget._ctor(self, "DYC_SlicedImage" ) self.images = {} self.mode = "slice13" self.texScale = data.texScale or 0x1 self.width = 0x64 self.height = 0x64 self:SetTextures(data) end) function DYC_SlicedImage:__tostring() return string.format( "%s (%s)" , self.name, self.mode) end function DYC_SlicedImage:SetTextures(data) assert(data.mode) self.images = {} self.mode = data.mode if self.mode == "slice13" or self.mode == "slice31" then local img = nil img = self:AddChild(Image(data.atlas, data.texname.."_1.tex" )) img.oriW, img.oriH = img:GetSize() img.imgPos = 0x1 self.images[0x1] = img img = self:AddChild(Image(data.atlas, data.texname.."_2.tex" )) img.oriW, img.oriH = img:GetSize() img.imgPos = 0x2 self.images[0x2] = img img = self:AddChild(Image(data.atlas, data.texname.."_3.tex" )) img.oriW, img.oriH = img:GetSize() img.imgPos = 0x3 self.images[0x3] = img if self.mode == "slice13" then assert(self.images[0x1].oriH == self.images[0x3].oriH, "Height must be equal!" ) assert(self.images[0x1].oriH == self.images[0x2].oriH, "Height must be equal!" ) else assert(self.images[0x1].oriW == self.images[0x3].oriW, "Width must be equal!" ) assert(self.images[0x1].oriW == self.images[0x2].oriW, "Width must be equal!" ) end return elseif self.mode == "slice33" then local img = nil for i = 0x1, 0x3 do for j = 0x1, 0x3 do img = self:AddChild(Image(data.atlas, data.texname.."_"..i..j..".tex" )) img.oriW, img.oriH = img:GetSize() img.imgPos = i * 0xa + j self.images[i * 0xa + j] = img if i > 0x1 then assert(self.images[i * 0xa + j].oriW == self.images[(i - 0x1) * 0xa + j].oriW, "Width must be equal!" ) end if j > 0x1 then assert(self.images[i * 0xa + j].oriH == self.images[i * 0xa + j - 0x1].oriH, "Height must be equal!" ) end end end return end error( "Mode not supported!" ) self:SetSize() end function DYC_SlicedImage:SetSize(w, h) w = w or self.width h = h or self.height if self.mode == "slice13" then local img1 = self.images[0x1] local img2 = self.images[0x2] local img3 = self.images[0x3] local scale = math.min(self.texScale, math.min(w / (img1.oriW + img3.oriW), h / img1.oriH)) local w1 = img1.oriW * scale local w3 = img3.oriW * scale local w2 = math.max(0x0, w - w1 - w3) img1:SetSize(w1, h) img2:SetSize(w2, h) img3:SetSize(w3, h) local x2 = (w1 - w3) / 0x2 local x1 = - w1 / 0x2 - w2 / 0x2 + x2 local x3 = w3 / 0x2 + w2 / 0x2 + x2 img1:SetPosition(x1, 0x0, 0x0) img2:SetPosition(x2, 0x0, 0x0) img3:SetPosition(x3, 0x0, 0x0) self.width = w1 + w2 + w3 self.height = h elseif self.mode == "slice31" then local img1 = self.images[0x1] local img2 = self.images[0x2] local img3 = self.images[0x3] local scale = math.min(self.texScale, math.min(h / (img1.oriH + img3.oriH), w / img1.oriW)) local h1 = img1.oriH * scale local h3 = img3.oriH * scale local h2 = math.max(0x0, h - h1 - h3) img1:SetSize(w, h1) img2:SetSize(w, h2) img3:SetSize(w, h3) local y2 = (h1 - h3) / 0x2 local y1 = - h1 / 0x2 - h2 / 0x2 + y2 local y3 = h3 / 0x2 + h2 / 0x2 + y2 img1:SetPosition(0x0, y1, 0x0) img2:SetPosition(0x0, y2, 0x0) img3:SetPosition(0x0, y3, 0x0) self.height = h1 + h2 + h3 self.width = w elseif self.mode == "slice33" then local imgs = self.images local scale = math.min(self.texScale, math.min(w / (imgs[0xb].oriW + imgs[0xd].oriW), h / (imgs[0xb].oriH + imgs[0x1f].oriH))) local ws, hs, xs, ys = {}, {}, {}, {} ws[0x1] = imgs[0xb].oriW * scale ws[0x3] = imgs[0xd].oriW * scale ws[0x2] = math.max(0x0, w - ws[0x1] - ws[0x3]) hs[0x1] = imgs[0xb].oriH * scale hs[0x3] = imgs[0x1f].oriH * scale hs[0x2] = math.max(0x0, h - hs[0x1] - hs[0x3]) xs[0x2] = (ws[0x1] - ws[0x3]) / 0x2 xs[0x1] = - ws[0x1] / 0x2 - ws[0x2] / 0x2 + xs[0x2] xs[0x3] = ws[0x3] / 0x2 + ws[0x2] / 0x2 + xs[0x2] ys[0x2] = (hs[0x1] - hs[0x3]) / 0x2 ys[0x1] = - hs[0x1] / 0x2 - hs[0x2] / 0x2 + ys[0x2] ys[0x3] = hs[0x3] / 0x2 + hs[0x2] / 0x2 + ys[0x2] for i = 0x1, 0x3 do for j = 0x1, 0x3 do imgs[i * 0xa + j]:SetSize(ws[j], hs[i]) imgs[i * 0xa + j]:SetPosition(xs[j], ys[i], 0x0) end end self.width = ws[0x1] + ws[0x2] + ws[0x3] self.height = hs[0x1] + hs[0x2] + hs[0x3] end end function DYC_SlicedImage:GetSize() return self.width, self.height end function DYC_SlicedImage:SetTint(r, g, b, a) for k, v in pairs(self.images) do v:SetTint(r, g, b, a) end end function DYC_SlicedImage:SetClickable(b) for k, v in pairs(self.images) do v:SetClickable(b) end end dycguis.SlicedImage = DYC_SlicedImage local DYC_Spinner = Class(Spinner, function(self, options, width, height, textinfo, editable, atlas, textures) Spinner._ctor(self, options, width, height, textinfo, editable, atlas, textures) end) function DYC_Spinner:GetSelectedHint() return self.options[self.selectedIndex].hint or "" end function DYC_Spinner:SetSelected(data, data2) if data == nil and data2 ~= nil then return self:SetSelected(data2) end for k, v in pairs(self.options) do if v.data == data then self:SetSelectedIndex(k) return true end end if data2 then return self:SetSelected(data2) else return false end end function DYC_Spinner:SetSelectedIndex(idx, ...) DYC_Spinner._base.SetSelectedIndex(self, idx, ...) if self.setSelectedIndexFn then self.setSelectedIndexFn(self) end end function DYC_Spinner:OnGainFocus() DYC_Spinner._base.OnGainFocus(self) if self.focusFn then self.focusFn(self) end end function DYC_Spinner:OnLoseFocus() DYC_Spinner._base.OnLoseFocus(self) if self.unfocusFn then self.unfocusFn(self) end end function DYC_Spinner:OnMouseButton(button, down, x, y, ...) DYC_Spinner._base.OnMouseButton(self, button, down, x, y, ...) if not down and button == MOUSEBUTTON_LEFT then if self.mouseLeftUpFn then self.mouseLeftUpFn(self) end end if not self.focus then return false end if down and button == MOUSEBUTTON_LEFT then if self.mouseLeftDownFn then self.mouseLeftDownFn(self) end end end dycguis.Spinner = DYC_Spinner local DYC_ImageButton = Class(Button, function(self, data) Button._ctor(self, "DYC_ImageButton" ) data = data or {} local atlas, normal, focus, disabled = data.atlas, data.normal, data.focus, data.disabled atlas = atlas or "images/ui.xml" normal = normal or "button.tex" focus = focus or "button_over.tex" disabled = disabled or "button_disabled.tex" self.width = data.width or 0x64 self.height = data.height or 0x1e self.screenScale = 0.9999 self.moveLayerTimer = 0x0 self.followScreenScale = data.followScreenScale self.draggable = data.draggable if data.draggable then self.clickoffset = Vector3(0x0, 0x0, 0x0) end self.dragging = false self.draggingTimer = 0x0 self.draggingPos = {x = 0x0, y = 0x0} self.keepTop = data.keepTop self.image = self:AddChild(Image()) self.image:MoveToBack() self.atlas = atlas self.image_normal = normal self.image_focus = focus or normal self.image_disabled = disabled or normal self.color_normal = data.colornormal or RGBAColor() self.color_focus = data.colorfocus or RGBAColor() self.color_disabled = data.colordisabled or RGBAColor() if data.cb then self:SetOnClick(data.cb) end if data.text then self:SetText(data.text) self:SetFont(data.font or NUMBERFONT) self:SetTextSize(data.fontSize or self.height * 0.75) local r, g, b, a = 0x1, 0x1, 0x1, 0x1 if data.textColor then r = data.textColor.r;g = data.textColor.g; b = data.textColor.b;a = data.textColor.a end self:SetTextColour(r, g, b, a) end self:SetTexture(self.atlas, self.image_normal) self:StartUpdating() end) function DYC_ImageButton:SetSize(w, h) w = w or self.width; h = h or self.height self.width = w; self.height = h self.image:SetSize(self.width, self.height) end function DYC_ImageButton:GetSize() return self.image:GetSize() end function DYC_ImageButton:SetTexture(atlas, tex) self.image:SetTexture(atlas, tex) self:SetSize() local c = self.color_normal self.image:SetTint(c.r, c.g, c.b, c.a) end function DYC_ImageButton:SetTextures(atlas, normal, focus, disabled) local default_textures = false if not atlas then atlas = atlas or "images/frontend.xml" normal = normal or "button_long.tex" focus = focus or "button_long_halfshadow.tex" disabled = disabled or "button_long_disabled.tex" default_textures = true end self.atlas = atlas self.image_normal = normal self.image_focus = focus or normal self.image_disabled = disabled or normal if self:IsEnabled() then if self.focus then self:OnGainFocus() else self:OnLoseFocus() end else self:OnDisable() end end function DYC_ImageButton:OnGainFocus() DYC_ImageButton._base.OnGainFocus(self) if self:IsEnabled() then self:SetTexture(self.atlas, self.image_focus) local c = self.color_focus self.image:SetTint(c.r, c.g, c.b, c.a) end if self.image_focus == self.image_normal then self.image:SetScale(1.2, 1.2, 1.2) end if self.focusFn then self.focusFn(self) end end function DYC_ImageButton:OnLoseFocus() DYC_ImageButton._base.OnLoseFocus(self) if self:IsEnabled() then self:SetTexture(self.atlas, self.image_normal) local c = self.color_normal self.image:SetTint(c.r, c.g, c.b, c.a) end if self.image_focus == self.image_normal then self.image:SetScale(0x1, 0x1, 0x1) end if self.unfocusFn then self.unfocusFn(self) end end function DYC_ImageButton:OnMouseButton(button, down, x, y, ...) DYC_ImageButton._base.OnMouseButton(self, button, down, x, y, ...) if not down and button == MOUSEBUTTON_LEFT and self.dragging then self.dragging = false if self.dragEndFn then self.dragEndFn(self) end end if not self.focus then return false end if self.draggable and button == MOUSEBUTTON_LEFT then if down then self.dragging = true self.draggingPos.x = x self.draggingPos.y = y end end end function DYC_ImageButton:OnControl(control, down, ...) if self.draggingTimer <= 0.3 then if DYC_ImageButton._base.OnControl(self, control, down, ...) then self:StartUpdating() return true end self:StartUpdating() end if not self:IsEnabled() or not self.focus then return end end function DYC_ImageButton:Enable() DYC_ImageButton._base.Enable(self) self:SetTexture(self.atlas, self.focus and self.image_focus or self.image_normal) local c = self.focus and self.color_focus or self.color_normal self.image:SetTint(c.r, c.g, c.b, c.a) if self.image_focus == self.image_normal then if self.focus then self.image:SetScale(1.2, 1.2, 1.2) else self.image:SetScale(0x1, 0x1, 0x1) end end end function DYC_ImageButton:Disable() DYC_ImageButton._base.Disable(self) self:SetTexture(self.atlas, self.image_disabled) local c = self.color_disabled or self.color_normal self.image:SetTint(c.r, c.g, c.b, c.a) end function DYC_ImageButton:OnUpdate(dt) dt = dt or 0x0 local newss = GetScreenScale() if self.followScreenScale and newss ~= self.screenScale then self:SetScale(newss) local offset = self:GetPosition() offset.x = offset.x * newss / self.screenScale offset.y = offset.y * newss / self.screenScale self.o_pos = offset self:SetPosition(offset) self.screenScale = newss end if self.draggable and self.dragging then self.draggingTimer = self.draggingTimer + dt local x, y = GetMouseScreenPos() local dx = x - self.draggingPos.x local dy = y - self.draggingPos.y self.draggingPos.x = x; self.draggingPos.y = y local offset = self:GetPosition() offset.x = offset.x + dx; offset.y = offset.y + dy self.o_pos = offset self:SetPosition(offset) end if not self.dragging then self.draggingTimer = 0x0 end self.moveLayerTimer = self.moveLayerTimer + dt if self.keepTop and self.moveLayerTimer > 0.5 then self.moveLayerTimer = 0x0 self:MoveToFront() end end dycguis.ImageButton = DYC_ImageButton local DYC_Window = Class(Widget, function(self) Widget._ctor(self, "DYC_Window" ) self.width = 0x190 self.height = 0x12c self.paddingX = 0x28 self.paddingY = 0x2a self.screenScale = 0.9999 self.currentLineY = 0x0 self.currentLineX = 0x0 self.lineHeight = 0x23 self.lineSpacingX = 0xa self.lineSpacingY = 0x3 self.fontSize = self.lineHeight * 0.9 self.font = NUMBERFONT self.titleFontSize = 0x28 self.titleFont = NUMBERFONT self.titleColor = RGBAColor(0x1, 0.7, 0.4) self.draggable = true self.dragging = false self.draggingPos = {x = 0x0, y = 0x0} self.draggableChildren = {} self.moveLayerTimer = 0x0 self.keepTop = false self.currentPageIndex = 0x1 self.pages = {} self.animTargetSize = nil self.bg = self:AddChild(DYC_SlicedImage({mode = "slice33" , atlas = "images/dyc_panel_shadow.xml" , texname = "dyc_panel_shadow" , texScale = 1.0,})) self.bg:SetSize(self.width, self.height) self.bg:SetTint(0x1, 0x1, 0x1, 0x1) self:SetCenterAlignment() self:AddDraggableChild(self.bg, true) self.root = self.bg:AddChild(Widget( "root" )) self.rootTL = self.root:AddChild(Widget( "rootTL" )) self.rootT = self.root:AddChild(Widget( "rootT" )) self.rootTR = self.root:AddChild(Widget( "rootTR" )) self.rootL = self.root:AddChild(Widget( "rootL" )) self.rootM = self.root:AddChild(Widget( "rootM" )) self.rootR = self.root:AddChild(Widget( "rootR" )) self.rootB = self.root:AddChild(Widget( "rootB" )) self.rootBL = self.root:AddChild(Widget( "rootBL" )) self.rootBR = self.root:AddChild(Widget( "rootBR" )) self:SetSize() self:SetOffset(0x0, 0x0, 0x0) self:StartUpdating() end) function DYC_Window:SetBottomAlignment() self.bg:SetVAnchor(ANCHOR_BOTTOM) self.bg:SetHAnchor(ANCHOR_MIDDLE) end function DYC_Window:SetBottomLeftAlignment() self.bg:SetVAnchor(ANCHOR_BOTTOM) self.bg:SetHAnchor(ANCHOR_LEFT) end function DYC_Window:SetTopLeftAlignment() self.bg:SetVAnchor(ANCHOR_TOP) self.bg:SetHAnchor(ANCHOR_LEFT) end function DYC_Window:SetCenterAlignment() self.bg:SetVAnchor(ANCHOR_MIDDLE) self.bg:SetHAnchor(ANCHOR_MIDDLE) end function DYC_Window:SetOffset(...) self.bg:SetPosition(...) end function DYC_Window:GetOffset() return self.bg:GetPosition() end function DYC_Window:SetSize(w, h) w = w or self.width; h = h or self.height self.width = w; self.height = h self.bg:SetSize(w, h) self.rootTL:SetPosition( - w / 0x2, h / 0x2, 0x0) self.rootT:SetPosition(0x0, h / 0x2, 0x0) self.rootTR:SetPosition(w / 0x2, h / 0x2, 0x0) self.rootL:SetPosition( - w / 0x2, 0x0, 0x0) self.rootM:SetPosition(0x0, 0x0, 0x0) self.rootR:SetPosition(w / 0x2, 0x0, 0x0) self.rootBL:SetPosition( - w / 0x2, - h / 0x2, 0x0) self.rootB:SetPosition(0x0, - h / 0x2, 0x0) self.rootBR:SetPosition(w / 0x2, - h / 0x2, 0x0) end function DYC_Window:GetSize() return self.width, self.height end function DYC_Window:SetTitle(str, font, fontSize, c) if not self.title then self.title = self.rootT:AddChild(DYC_Text(NUMBERFONT, 0xa)) end str = str or self.title:GetString() ; font = font or self.titleFont; fontSize = fontSize or self.titleFontSize; c = c or self.titleColor self.titleFont = font; self.titleFontSize = fontSize; self.titleColor = c self.title:SetString(str) self.title:SetFont(font) self.title:SetSize(fontSize) self.title:SetPosition(0x0, - fontSize / 0x2 * 1.3 - self.paddingY, 0x0) self.title:SetColor(c.r or c[0x1] or 0x1, c.g or c[0x2] or 0x1, c.b or c[0x3] or 0x1, c.a or c[0x4] or 0x1) end function DYC_Window:GetPage(pageIndex) pageIndex = pageIndex or self.currentPageIndex pageIndex = math.max(0x1, math.floor(pageIndex)) while self.pages[pageIndex] == nil do table.insert(self.pages, {root = self.rootTL:AddChild(Widget( "rootPage"..pageIndex)), contents = {},}) end return self.pages[pageIndex] end function DYC_Window:SetCurrentPage(pageIndex) pageIndex = math.max(0x1, math.floor(pageIndex)) self.currentPageIndex = pageIndex self.currentLineY = 0x0 self.currentLineX = 0x0 return self:GetPage() end function DYC_Window:ShowPage(pageIndex) pageIndex = pageIndex or self.currentPageIndex pageIndex = math.max(0x1, math.min(math.floor(pageIndex), #self.pages)) self:SetCurrentPage(pageIndex) for i = 0x1, #self.pages do self:ToggleContents(i, i == pageIndex) end if self.pageChangeFn then self.pageChangeFn(self, pageIndex) end end function DYC_Window:ShowNextPage() local pageIndex = self.currentPageIndex + 0x1 if pageIndex > #self.pages then pageIndex = 0x1 end self:ShowPage(pageIndex) end function DYC_Window:ShowPreviousPage() local pageIndex = self.currentPageIndex - 0x1 if pageIndex < 0x1 then pageIndex = #self.pages end self:ShowPage(pageIndex) end function DYC_Window:ClearPages() if #self.pages <= 0x0 then return end for i = 0x1, #self.pages do self:ClearContents(i) end end function DYC_Window:AddContent(w, width) local page = self:GetPage() local uie = page.root:AddChild(w) if not width then if uie.GetRegionSize then width = uie:GetRegionSize() elseif uie.GetWidth then width = uie:GetWidth() elseif uie.width then width = uie.width end end width = width or 0x64 uie:SetPosition(self.paddingX + self.currentLineX + width / 0x2, - self.paddingY - self.currentLineY - self.lineHeight * 0.5, 0x0) self.currentLineX = self.currentLineX + width + self.lineSpacingX TableAdd(page.contents, uie) return uie end function DYC_Window:ToggleContents(pageIndex, b) local page = self:GetPage(pageIndex) if b then page.root:Show() else page.root:Hide() end end function DYC_Window:ClearContents(pageIndex) pageIndex = pageIndex or self.currentPageIndex for k, v in pairs(self:GetPage(pageIndex).contents) do v:Kill() end self:GetPage(pageIndex).contents = {} self.currentLineY = 0x0 self.currentLineX = 0x0 end function DYC_Window:NewLine(k) self.currentLineY = self.currentLineY + (k or 0x1) * self.lineHeight + self.lineSpacingY self.currentLineX = 0x0 end function DYC_Window:AddDraggableChild(child, includeChildren) TableAdd(self.draggableChildren, child) if includeChildren then for k, v in pairs(child.children) do self:AddDraggableChild(v, true) end end end function DYC_Window:OnRawKey(key, down, ...) local returnValue = DYC_Window._base.OnRawKey(self, key, down, ...) if not self.focus then return false end return returnValue end function DYC_Window:OnControl(control, down, ...) local returnValue = DYC_Window._base.OnControl(self, control, down, ...) if not self.focus then return false end return returnValue end function DYC_Window:OnMouseButton(button, down, x, y, ...) local returnValue = DYC_Window._base.OnMouseButton(self, button, down, x, y, ...) if not down and button == MOUSEBUTTON_LEFT then self.dragging = false end if not self.focus then return false end if self.draggable and button == MOUSEBUTTON_LEFT then if down then local deepestFocus = self:GetDeepestFocus() if deepestFocus and TableContains(self.draggableChildren, deepestFocus) then self.dragging = true self.draggingPos.x = x self.draggingPos.y = y end end end return returnValue end function DYC_Window:Toggle(b, isOK) b = b ~= nil and b or not self.shown if b then self:Show() else self:Hide() end if self.toggleFn then self.toggleFn(self, b) end if not b and isOK and self.okFn then self.okFn(self) end if not b and not isOK and self.cancelFn then self.cancelFn(self) end end function DYC_Window:AnimateSize(tw, th, speed) if tw and th then self.animTargetSize = {w = tw, h = th} self.animSpeed = speed or 0x5 end end function DYC_Window:OnUpdate(dt) dt = dt or 0x0 if self.animTargetSize and dt > 0x0 then local w, h = self:GetSize() if math.abs(w - self.animTargetSize.w) < 0x1 then self:SetSize(self.animTargetSize.w, self.animTargetSize.h) self.animTargetSize = nil else self:SetSize(Lerp(w, self.animTargetSize.w, self.animSpeed * dt), Lerp(h, self.animTargetSize.h, self.animSpeed * dt)) end end local newss = GetScreenScale() if newss ~= self.screenScale then self.bg:SetScale(newss) local offset = self:GetOffset() offset.x = offset.x * newss / self.screenScale offset.y = offset.y * newss / self.screenScale self:SetOffset(offset) self.screenScale = newss end if self.draggable and self.dragging then local x, y = GetMouseScreenPos() local dx = x - self.draggingPos.x local dy = y - self.draggingPos.y self.draggingPos.x = x; self.draggingPos.y = y local offset = self:GetOffset() offset.x = offset.x + dx; offset.y = offset.y + dy self:SetOffset(offset) end self.moveLayerTimer = self.moveLayerTimer + dt if self.keepTop and self.moveLayerTimer > 0.5 then self.moveLayerTimer = 0x0 self:MoveToFront() end end dycguis.Window = DYC_Window local DYC_Banner = Class(DYC_Window, function(self, data) DYC_Window._ctor(self) self:SetTopLeftAlignment() self.bg:SetClickable(false) self.bg:SetTint(0x1, 0x1, 0x1, 0x0) self.paddingX = 0x23 self.paddingY = 0x23 self.lineHeight = 0x20 self.fontSize = 0x20 self.font = DEFAULTFONT self.bannerColor = data.color or RGBAColor() self.bannerText = self:AddContent(DYC_Text({font = self.font, fontSize = self.fontSize, alignH = ANCHOR_LEFT, text = data.text or "???" , color = self.bannerColor,})) local windowW, windowH = self.currentLineX + self.paddingX * 0x2, self.lineHeight + self.paddingY * 0x2 self:SetSize(windowW, windowH) self.windowW = windowW self.bannerText:AnimateIn() self:SetOffset(0x2bc, - windowH / 0x2) self.shouldFadeIn = true self.bannerOpacity = 0x0 self.bannerTimer = data.duration or 0x5 self.bannerIndex = 0x1 end) function DYC_Banner:SetShouldFadeOut() self.shouldFadeIn = false end function DYC_Banner:OnUpdate(dt) DYC_Banner._base.OnUpdate(self, dt) dt = dt or 0x0 if dt > 0x0 then self.bannerTimer = self.bannerTimer - dt if self.shouldFadeIn then self.bannerOpacity = math.min(0x1, self.bannerOpacity + dt * 0x3) else self.bannerOpacity = self.bannerOpacity - dt if self.bannerOpacity <= 0x0 then if self.bannerHolder then self.bannerHolder:RemoveBanner(self) end self:Kill() end end if self.bannerOpacity > 0x0 then self.bg:SetTint(0x1, 0x1, 0x1, self.bannerOpacity) local c = self.bannerColor self.bannerText:SetColor(c.r or c[0x1] or 0x1, c.g or c[0x2] or 0x1, c.b or c[0x3] or 0x1, self.bannerOpacity) local w, h = self:GetSize() local offset = self:GetOffset() local x, y = offset.x, offset.y local tX, tY = w / 0x2 * self.screenScale,(h / 0x2 - h * self.bannerIndex) * self.screenScale local p = 0.1 self:SetOffset(Lerp(x, tX, p), Lerp(y, tY, p)) end end end dycguis.Banner = DYC_Banner local DYC_BannerHolder = Class(DYC_Root, function(self, data) data = data or {} DYC_Root._ctor(self, data) self.banners = {} self.bannerInfos = {} self.bannerInterval = data.interval or 0.3 self.bannerShowTimer = 0x3e7 self.bannerSound = data.sound or "dontstarve/HUD/XP_bar_fill_unlock" self.maxBannerNum = data.max or 0x6 self:StartUpdating() end) function DYC_BannerHolder:PushMessage(text, duration, color, playSound) table.insert(self.bannerInfos, {text = text, duration = duration, color = color, playSound = playSound}) end function DYC_BannerHolder:ShowMessage(text, duration, color, playSound) local banner = self:AddChild(DYC_Banner({text = text, duration = duration, color = color})) self:AddBanner(banner) local player = DYCGetPlayer() if playSound and player and player.SoundEmitter and self.bannerSound then player.SoundEmitter:PlaySound(self.bannerSound) end end function DYC_BannerHolder:AddBanner(banner) banner.bannerHolder = self local banners = self.banners table.insert(banners, 0x1, banner) for i = 0x1, #banners do banners[i].bannerIndex = i end end function DYC_BannerHolder:RemoveBanner(banner) for k, v in pairs(self.banners) do if v == banner then table.remove(self.banners, k) break end end for k, v in pairs(self.banners) do v.bannerIndex = k end end function DYC_BannerHolder:OnUpdate(dt) dt = dt or 0x0 local banners = self.banners local infos = self.bannerInfos if dt > 0x0 and #banners > 0x0 then for i = 0x1, #banners do local banner = banners[i] if i > self.maxBannerNum then banner:SetShouldFadeOut() elseif banner.bannerTimer <= 0x0 then banner:SetShouldFadeOut() end end end if dt > 0x0 and #infos > 0x0 then self.bannerShowTimer = self.bannerShowTimer + dt if self.bannerShowTimer >= self.bannerInterval then self.bannerShowTimer = 0x0 local info = infos[0x1] table.remove(infos, 0x1) if #infos <= 0x0 then self.bannerShowTimer = 0x3e7 end self:ShowMessage(info.text, info.duration, info.color, info.playSound) end end end dycguis.BannerHolder = DYC_BannerHolder local DYC_MessageBox = Class(DYC_Window, function(self, data) DYC_Window._ctor(self) self.messageText = self.rootM:AddChild(DYC_Text({font = self.font, fontSize = data.fontSize or self.fontSize, color = RGBAColor(0.9, 0.9, 0.9, 0x1),})) self.strings = data.strings self.callback = data.callback local closeButton = self.rootTR:AddChild(DYC_ImageButton({width = 0x28, height = 0x28, normal = "button_checkbox1.tex" , focus = "button_checkbox1.tex" , disabled = "button_checkbox1.tex" , colornormal = RGBAColor(0x1, 0x1, 0x1, 0x1), colorfocus