ickable(false) self.stackText = self:AddChild(Text(NUMBERFONT, data.width and data.width / self.oriWidth * 0x26 or 0xf)) self.stackText:SetString(data.buffInfo.buff.maxStack > 0x1 and data.buffInfo.stack or "" ) self.buffInfo = data.buffInfo self.cdCb = function(info, cooldown, percent) self:SetCooldownPercent(percent) end self.stackCb = function(info, stack) self.stackText:SetString(data.buffInfo.buff.maxStack > 0x1 and stack or "" ) end self.buffInfo:RegisterEvent( "cooldownchange" , self.cdCb) self.buffInfo:RegisterEvent( "stackchange" , self.stackCb) if self.buffInfo.percent then self:SetCooldownPercent(self.buffInfo.percent) end self.buffInfo:RegisterEvent( "dispose" , function(info) self:Kill() end) if self.buffInfo.buff.type == "positive" then self.frame:SetTint(0x0, 0x1, 0x0, 0.5) elseif self.buffInfo.buff.type == "negative" then self.frame:SetTint(0x1, 0x0, 0x0, 0.5) end if data.width and data.height then self:SetSize(data.width, data.height) end end) function DYC_BuffTile:SetCooldownPercent(p) p = p or 0x1 p = math.max(0x0, math.min(p, 0x1)) if not self.cdAnim.shown then self.cdAnim:Show() end self.cdAnim:GetAnimState():SetPercent( "recharge" , p) if p == 0x1 then if self.buffInfo.buff.constant then self.cdAnim:GetAnimState():PlayAnimation( "frame" ) else self.cdAnim:GetAnimState():PlayAnimation( "frame_pst" ) end end end function DYC_BuffTile:SetSize(w, h) w = w or self.width or self.oriWidth; h = h or self.height or self.oriHeight self.width = w; self.height = h self.bg:SetSize(self.width, self.height) self.frame:SetSize(self.width, self.height) self.stackText:SetRegionSize(self.width, self.height) self.stackText:SetHAlign(ANCHOR_RIGHT) self.stackText:SetVAlign(ANCHOR_BOTTOM) if self.image then self.image:SetSize(self.width, self.height) end self.cdAnim:SetScale( - self.width / self.oriWidth, self.height / self.oriHeight, 0x1) end function DYC_BuffTile:GetSize() return self.width or self.oriWidth, self.height or self.oriHeight end function DYC_BuffTile:S