 self:AddContent(DYC_Text({font = hintFont, fontSize = self.fontSize * titleScale, text = data.action or "???" , color = data.actionColor or colorAction,})) end if data.prefix and #data.prefix > 0x0 then local prefixText = self:AddContent(DYC_Text({font = titleFont, fontSize = self.fontSize * titleScale, text = data.prefix or "???" , color = data.prefixColor or colorDefault,})) end if data.name and #data.name > 0x0 then local nameText = self:AddContent(DYC_Text({font = titleFont, fontSize = self.fontSize * nameScale, text = data.name or "???" , color = data.nameColor and data.nameColor:A(alpha) or colorDefault,})) end if data.suffix and #data.suffix > 0x0 then local suffixText = self:AddContent(DYC_Text({font = titleFont, fontSize = self.fontSize * titleScale, text = data.suffix or "???" , color = data.suffixColor or colorDefault,})) end calcWidth = math.max(calcWidth, self.currentLineX) calcHeight = calcHeight + self.lineHeight NewLine(0.4) calcHeight = calcHeight + self.lineHeight * 0.4 if data.action2 and #data.action2 > 0x0 then multiLines = true NewLine(0x1) local action2Text = self:AddContent(DYC_Text({font = hintFont, fontSize = self.fontSize, text = data.action2 or "???" , color = data.action2Color or colorAction,})) calcWidth = math.max(calcWidth, self.currentLineX) calcHeight = calcHeight + self.lineHeight if data.quality then local qualityText = self:AddContent(DYC_Text({font = self.font, fontSize = self.fontSize, text = data.quality or "" , color = colorDefault})) calcWidth = math.max(calcWidth, self.currentLineX) end end if data.buffSource and #data.buffSource > 0x0 then multiLines = true NewLine(0x1) local sourceText = self:AddContent(DYC_Text({font = self.font, fontSize = self.fontSize, text = data.buffSource or "???" , color = data.action2Color or colorOther,})) calcWidth = math.max(calcWidth, self.currentLineX) calcHeight = calcHeight + self.lineHeight end if data.rarity and #data.rarity > 0x0 then multiLines = true NewLine(0x1) local rarityText = self:AddContent(DYC_Text({font = self.font, fontSize = self.fontSize, text = data.rarity or "" , color = colorDefault})) calcWidth = math.max(calcWidth, self.currentLineX) calcHeight = calcHeight + self.lineHeight end if data.lines then for k, v in pairs(data.lines) do multiLines = true NewLine(0x1) local newText = self:AddContent(DYC_Text({font = self.font, fontSize = self.fontSize, text = v.text or "" , color = v.color and v.color:A(alpha) or colorOther})) calcWidth = math.max(calcWidth, self.currentLineX) calcHeight = calcHeight + self.lineHeight end end if data.buffInfos and next(data.buffInfos) then multiLines = true NewLine(0x1) for k, info in pairs(data.buffInfos) do local tileSize = self.lineHeight local buffTile = self:AddContent(DYC_BuffTile({buffInfo = info, width = tileSize, height = tileSize,})) buffTile:SetClickable(false) end calcWidth = math.max(calcWidth, self.currentLineX) calcHeight = calcHeight + self.lineHeight end if data.encLines then for k, v in pairs(data.encLines) do if not v.isHidden and v.text and #v.text > 0x0 then multiLines = true NewLine(0x1) local newText = self:AddContent(DYC_Text({font = self.font, fontSize = self.fontSize, text = v.text, color = v.color and v.color:A(alpha) or colorEnc})) calcWidth = math.max(calcWidth, self.currentLineX) calcHeight = calcHeight + self.lineHeight end end end NewLine(2.5) local desText = nil if data.des and #data.des > 0x0 then multiLines = true desText = self:AddContent(DYC_Text({font = self.font, fontSize = self.fontSize, text = data.des or "" , color = data.desColor and data.desColor:A(alpha) or colorDes})) local desWidth = desText:GetWidth() local minWidth = 0xe6 if desWidth > calcWidth then if desWidth >= minWidth and calcWidth < minWidth then calcWidth = minWidth elseif desWidth < minWidth and calcWidth < minWidth then calcWidth = desWidth end end end calcWidth = math.min(calcWidth, maxWidth) if not multiLines then calcHeight = calcHeight - self.lineHeight * 0.4 end local windowW = calcWidth + self.paddingX * 0x2 local windowH = calcHeight + self.paddingY * 0x2 if desText then local oldDesWidth = desText:GetWidth() desText:SetRegionSize(calcWidth, self.fontSize * 0xa) desText:SetPosition(windowW / 0x2, - calcHeight - self.paddingY - desText:GetHeight() / 0x2, 0x0) desText:SetHAlign(ANCHOR_LEFT) desText:SetVAlign(ANCHOR_TOP) desText:EnableWordWrap(true) local multiLineScale = dycguis.multiLineScale or 0x1 windowH = windowH + self.fontSize * multiLineScale * (math.floor((oldDesWidth - 0.0001) / desText:GetWidth()) + 0x1) end self:SetSize(windowW, windowH) end function DYC_ObjectDetailWindow:SetObjectDetail(data) self:RefreshPage(data) end function DYC_ObjectDetailWindow:OnUpdate(dt) DYC_ObjectDetailWindow._base.OnUpdate(self, dt) dt = dt or 0x0 end dycguis.ObjectDetailWindow = DYC_ObjectDetailWindow return dycguis 